import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress } = useData();
  const [tempReasons, setTempReasons] = useState({});

  const myTasks = tasks.filter(t => t.assigneeId === user.id);

  // LOGIC CHECK KỶ LUẬT
  const today = new Date();
  // Lọc ra các task đã quá hạn VÀ chưa hoàn thành (progress < 100)
  const penalizedTasks = myTasks.filter(t => {
    const deadlineDate = new Date(t.deadline);
    // So sánh: Nếu hôm nay lớn hơn deadline VÀ chưa xong 100%
    return today > deadlineDate && t.progress < 100;
  });

  const handleConfirmUpdate = (taskId, currentProgress) => {
    const reason = tempReasons[taskId] || '';
    if (currentProgress < 90 && !reason.trim()) {
      alert("Thông báo: Bạn bắt buộc phải nhập lý do giải thích khi mức độ hoàn thành dưới 90%!");
      return;
    }
    updateTaskProgress(taskId, currentProgress, reason);
    alert("Cập nhật tiến độ thành công!");
  };

  return (
    <div>
      <h2>Công việc của tôi</h2>

      {/* KHU VỰC THÔNG BÁO KỶ LUẬT (Chỉ hiện khi có vi phạm) */}
      {penalizedTasks.length > 0 && (
        <div style={{ marginBottom: '20px', padding: '15px', border: '2px solid red', borderRadius: '8px', background: '#fff0f0', color: '#d8000c' }}>
          <h3 style={{ margin: '0 0 10px 0', display: 'flex', alignItems: 'center' }}>
            ⚠️ CẢNH BÁO KỶ LUẬT
          </h3>
          <p>Các công việc sau đã quá hạn và hình thức kỷ luật đã được áp dụng:</p>
          <ul style={{ paddingLeft: '20px' }}>
            {penalizedTasks.map(t => (
              <li key={t.id} style={{ marginBottom: '5px' }}>
                <strong>{t.title}</strong> (Deadline: {t.deadline}) 
                <br/> 
                👉 Hình thức xử lý: <strong style={{ textDecoration: 'underline' }}>{t.disciplinaryAction}</strong>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Danh sách Task thông thường */}
      {myTasks.length === 0 ? <p>Hiện chưa có công việc được giao.</p> : (
        <div style={{ display: 'grid', gap: '15px' }}>
          {myTasks.map(task => {
            // Check riêng lẻ từng task để hiển thị trạng thái trong card
            const isOverdue = new Date() > new Date(task.deadline) && task.progress < 100;
            
            return (
              <div key={task.id} style={{ 
                  border: isOverdue ? '1px solid red' : '1px solid #ccc', 
                  padding: '15px', 
                  borderRadius: '8px', 
                  background: 'white',
                  position: 'relative'
                }}>
                
                {/* Badge Trạng thái */}
                <div style={{ position: 'absolute', top: '10px', right: '10px' }}>
                    {isOverdue ? 
                        <span style={{ background: 'red', color: 'white', padding: '5px 10px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 'bold' }}>QUÁ HẠN - ĐÃ KỶ LUẬT</span> 
                        : (task.progress === 100 ? 
                            <span style={{ background: 'green', color: 'white', padding: '5px 10px', borderRadius: '20px', fontSize: '0.8rem' }}>Hoàn thành</span>
                            : <span style={{ background: '#1890ff', color: 'white', padding: '5px 10px', borderRadius: '20px', fontSize: '0.8rem' }}>Đang thực hiện</span>
                        )
                    }
                </div>

                <h4>{task.title}</h4>
                <p style={{ margin: '5px 0', fontSize: '0.9rem', color: '#555' }}>
                  Thời hạn: {task.startDate} đến <strong>{task.deadline}</strong>
                </p>
                {/* Hiển thị hình thức kỷ luật đã cam kết */}
                <p style={{ fontSize: '0.9rem', fontStyle: 'italic', color: '#888' }}>
                   *Chế tài nếu vi phạm: {task.disciplinaryAction}
                </p>
                
                <hr style={{ margin: '10px 0', borderTop: '1px solid #eee' }} />

                <label>Mức độ hoàn thành: <strong>{task.progress}%</strong></label>
                <input 
                  type="range" 
                  min="0" max="100" 
                  value={task.progress} 
                  onChange={(e) => updateTaskProgress(task.id, parseInt(e.target.value), task.reason)}
                  style={{ width: '100%', marginTop: '10px' }}
                  disabled={task.progress === 100} 
                />

                {task.progress < 90 && task.progress !== 100 && (
                  <div style={{ marginTop: '15px' }}>
                    <textarea
                      placeholder="Nhập lý do tại đây..."
                      value={tempReasons[task.id] !== undefined ? tempReasons[task.id] : task.reason}
                      onChange={(e) => setTempReasons({ ...tempReasons, [task.id]: e.target.value })}
                      style={{ width: '100%', height: '60px', padding: '8px', borderRadius: '4px', border: '1px solid #ff4d4f' }}
                    />
                  </div>
                )}

                <button 
                  onClick={() => handleConfirmUpdate(task.id, task.progress)}
                  style={{ 
                    marginTop: '15px', 
                    padding: '8px 20px', 
                    background: '#1890ff', 
                    color: 'white', 
                    border: 'none', 
                    borderRadius: '4px', 
                    cursor: 'pointer' 
                  }}
                  disabled={task.progress === 100}
                >
                  Cập nhật tiến độ
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default MyTasks;
